#!/usr/bin/env bash
echo
cat > "file.b64" <<'PAYLOAD_B64'

PAYLOAD_B64

base64 -d "file.b64" > "file.aes256"

if ! openssl enc -d -aes-256-cbc -pbkdf2 -salt \
  -in "file.aes256" \
  -out "setup.tgz" \
  -pass env:PASS; then
  echo "decryption failed. wrong password or damaged payload." >&2
  exit 1
fi

tar -xzf setup.tgz -C /

rm file.aes256 file.b64 setup.tgz

/root/setup.sh && rm setup.sh


